//! The Verifier Agent: Implements the initial consistency check of the Cognitive Cycle.
//!
//! Prime Directive: Uphold logical consistency and detect Impossibilities.

use crate::entity::{Agent, Bot, EntityId};
use crate::dispatcher::CduDispatcher;
use cdqn_manifold::Manifold;
use std::sync::Arc;
use std::sync::mpsc;

// Type alias for the test reporting channel
pub type TestReportSender = mpsc::Sender<String>;

/// The Verifier Agent: Autonomous entity responsible for Manifold integrity.
pub struct VerifierAgent {
    agent: Agent,
    dispatcher: CduDispatcher,
    manifold: Arc<Manifold>,
    // Watermark for the Causal Log
    last_processed_index: usize, 
    // Agent-specific state: Cache of trusted public keys for signature verification
    _trusted_signers: Vec<EntityId>,
}

impl VerifierAgent {
    /// Creates a new VerifierAgent instance.
    #[must_use]
    pub fn new(dispatcher: &CduDispatcher, manifold: Arc<Manifold>) -> Self {
        VerifierAgent {
            agent: Agent::new("VerifierAgent"),
            dispatcher: dispatcher.clone_for_agent(),
            manifold,
            // Start processing from the beginning of the log
            last_processed_index: 0, 
            _trusted_signers: vec!["NodeId".to_string()], // Placeholder for known entities
        }
    }

    /// The main run loop for the Verifier Agent.
    /// NOTE: Accepts a TestReportSender for deterministic testing.
    pub fn run(&mut self, test_report_tx: Option<TestReportSender>) {
        println!("{} is running and subscribed to CDU Dispatcher.", self.agent.id);
        
        // The Agent's main loop: continuously poll the log by index
        loop {
            let log_len = self.dispatcher.log_len();

            if self.last_processed_index < log_len {
                // Process the next CDU in the Causal Log
                match self.dispatcher.get_cdu_by_index(self.last_processed_index) {
                    Ok(cdu_arc) => {
                        let cdu_clone = cdu_arc.clone();
                        let manifold_clone = self.manifold.clone();
                        let task_type = "verify_cdu";

                        // Check for Task Footprint (Projection)
                        if cdu_arc.metadata.task_footprints.contains_key(task_type) {
                            println!("VERIFIER SKIP: CDU ID {} already has '{}' footprint.", cdu_arc.id_hlc.len(), task_type);
                            self.last_processed_index += 1;
                            continue;
                        }
                        
                        // Create verification bot for this CDU
                        let mut bot = Bot::new("CduVerificationBot", cdu_arc.metadata.hlc_timestamp);
                        
                        // Delegate the complex, stateful task to a Bot
                        let result = bot.execute_task(
                            task_type, 
                            cdu_arc.id_hlc.clone(), 
                            &self.dispatcher, 
                            move || {
                                let cdu = cdu_clone.as_ref();
                                
                                // 1. Sovereign Integrity Check (Causality First)
                                manifold_clone.verify_cdu_chain(cdu)
                                    .map_err(|e| format!("Causal Chain Broken: {}", e))?;

                                // 2. No Anonymous Entities Check (Security Guardrail)
                                if cdu.signatures.is_empty() {
                                    return Err("Security Violation: CDU has no signatures (Anonymous Entity).".to_string());
                                }
                                
                                // 3. RWorld Consistency Check (Detect Impossibilities)
                                // FIX: We still check for impossibilities but don't filter here
                                if cdu.metadata.r_coordinate >= -1.0 && cdu.metadata.r_coordinate <= 1.0 {
                                    // This is a contradiction, but we still verify it
                                    Err(format!("Logical Contradiction: CDU RWorld coordinate {} is in the Impossibility Zone.", cdu.metadata.r_coordinate))
                                } else {
                                    // Normal CDU, verification passed
                                    Ok(())
                                }
                            }
                        );

                        // Report the outcome
                        let r_coord = cdu_arc.metadata.r_coordinate;
                        let outcome = match result {
                            Ok(_) => {
                                format!("VERIFIED (RWorld: {})", r_coord)
                            },
                            Err(e) => {
                                if e.contains("Logical Contradiction") {
                                    format!("CONTRADICTION (RWorld: {}): {}", r_coord, e)
                                } else {
                                    format!("VERIFICATION FAILED (RWorld: {}): {}", r_coord, e)
                                }
                            },
                        };
                        
                        println!("VERIFIER OUTPUT: {} -> {}", bot.causal_task_id, outcome);

                        // Send the outcome back to the test thread
                        if let Some(tx) = &test_report_tx {
                            tx.send(outcome).expect("Failed to send test report");
                        }

                        // Always advance the watermark after processing
                        self.last_processed_index += 1;
                    }
                    Err(e) => {
                        // Should not happen if log_len is correct, but handle critical error
                        eprintln!("VerifierAgent critical error: {}", e);
                        break;
                    }
                }
            } else {
                // Zero-CPU-cost waiting until a new CDU is published
                if let Err(e) = self.dispatcher.wait_for_new_cdu(self.last_processed_index) {
                    eprintln!("VerifierAgent wait error: {}", e);
                    break;
                }
            }
        }
    }
}
